<template>
    <el-dropdown trigger="click" @command="handleSetSize">
        <div>
            <svg-icon className="sizeselect-icon" icon-class="head-size" />
        </div>
        <el-dropdown-menu slot="dropdown">
            <el-dropdown-item :disabled="size==='medium'" command="medium">Medium</el-dropdown-item>
            <el-dropdown-item :disabled="size==='small'" command="small">Small</el-dropdown-item>
            <el-dropdown-item :disabled="size==='mini'" command="mini">Mini</el-dropdown-item>
        </el-dropdown-menu>
    </el-dropdown>
</template>

<script>
    export default {
        name:'size-select',
        computed: {
            size() {
                return this.$store.getters.size
            }
        },
        methods: {
            handleSetSize(size) {
                this.$ELEMENT.size = size
                this.$store.dispatch('setSize', size)
                this.refreshView()
                this.$message({
                    message: 'Switch Size Success',
                    type: 'success'
                })
            },
            refreshView() {
                // In order to make the cached page re-rendered
                const { fullPath } = this.$route
                this.$nextTick(() => {
                    this.$router.replace({
                         path: '/redirect' + fullPath
                    })
                })
            }
        }
    }
</script>

<style ref="stylesheet" lang="scss" scoped>
    .sizeselect-icon {
        display: inline-block;
        cursor: pointer;
        color: #606266;
        width:20px;
        height:20px;
        vertical-align:middle;
    }
</style>



